/**
 * Configuration file for Deepgram API Key
 *
 * IMPORTANT: This file is generated by Vercel from the DEEPGRAM_API_KEY environment variable.
 * Set the environment variable in your Vercel project settings:
 * Project Settings → Environment Variables → DEEPGRAM_API_KEY=<your-key>
 *
 * Get your free API key from: https://console.deepgram.com
 * Free tier: 300 minutes/month of transcription
 */

(function() {
  'use strict';

  // This will be injected by Vercel's build process
  window._DEEPGRAM_API_KEY = typeof DEEPGRAM_API_KEY !== 'undefined'
    ? DEEPGRAM_API_KEY
    : ''; // Will fallback to Web Speech API if empty
})();
